401	
402	static void *
403	njs_mp_alloc_small(njs_mp_t *mp, size_t size)
404	{
405	    u_char            *p;
406	    njs_mp_page_t     *page;
407	    njs_mp_slot_t     *slot;
408	    njs_queue_link_t  *link;
409	
410	    p = NULL;
411	
412	    if (size <= mp->page_size / 2) {
413	
414	        /* Find a slot with appropriate chunk size. */
415	        for (slot = mp->slots; slot->size < size; slot++) { /* void */ }
416	
417	        size = slot->size;
418	
419	        if (njs_fast_path(!njs_queue_is_empty(&slot->pages))) {
420	
421	            link = njs_queue_first(&slot->pages);
422	            page = njs_queue_link_data(link, njs_mp_page_t, link);
423	
424	            p = njs_mp_page_addr(mp, page);
425	            p += njs_mp_alloc_chunk(page->map, size);
426	
427	            page->chunks--;
428	
429	            if (page->chunks == 0) {
430	                /*
431	                 * Remove full page from the mp chunk slot list
432	                 * of pages with free chunks.
433	                 */
434	                njs_queue_remove(&page->link);
435	            }
436	
437	        } else {
438	            page = njs_mp_alloc_page(mp);
439	
440	            if (njs_fast_path(page != NULL)) {
441	
442	                njs_queue_insert_head(&slot->pages, &page->link);
443	
444	                /* Mark the first chunk as busy. */
445	                page->map[0] = 0x80;
446	                page->map[1] = 0;
447	                page->map[2] = 0;
448	                page->map[3] = 0;
449	
450	                /* slot->chunks are already one less. */
451	                page->chunks = slot->chunks;
452	                page->size = size >> mp->chunk_size_shift;
453	
454	                p = njs_mp_page_addr(mp, page);
455	            }
456	        }
457	
458	    } else {
459	        page = njs_mp_alloc_page(mp);
460	
461	        if (njs_fast_path(page != NULL)) {
462	            page->size = mp->page_size >> mp->chunk_size_shift;
463	
464	            p = njs_mp_page_addr(mp, page);
465	        }
466	
467	#if (NJS_DEBUG)
468	        size = mp->page_size;
469	#endif
470	    }
471	
472	    njs_debug_alloc("mp chunk:%uz alloc: %p\n", size, p);
473	
474	    return p;
475	}
