477	
478	static njs_uint_t
479	njs_mp_alloc_chunk(uint8_t *map, njs_uint_t size)
480	{
481	    uint8_t     mask;
482	    njs_uint_t  n, offset;
483	
484	    offset = 0;
485	    n = 0;
486	
487	    /* The page must have at least one free chunk. */
488	
489	    for ( ;; ) {
490	        if (map[n] != 0xff) {
491	
492	            mask = 0x80;
493	
494	            do {
495	                if ((map[n] & mask) == 0) {
496	                    /* A free chunk is found. */
497	                    map[n] |= mask;
498	                    return offset;
499	                }
500	
501	                offset += size;
502	                mask >>= 1;
503	
504	            } while (mask != 0);
505	
506	        } else {
507	            /* Fast-forward: all 8 chunks are occupied. */
508	            offset += size * 8;
509	        }
510	
511	        n++;
512	    }
513	}
514	
515	
516	static njs_mp_page_t *
517	njs_mp_alloc_page(njs_mp_t *mp)
518	{
519	    njs_mp_page_t     *page;
520	    njs_mp_block_t    *cluster;
521	    njs_queue_link_t  *link;
522	
523	    if (njs_queue_is_empty(&mp->free_pages)) {
524	        cluster = njs_mp_alloc_cluster(mp);
525	        if (njs_slow_path(cluster == NULL)) {
526	            return NULL;
527	        }
528	    }
529	
530	    link = njs_queue_first(&mp->free_pages);
531	    njs_queue_remove(link);
532	
533	    page = njs_queue_link_data(link, njs_mp_page_t, link);
534	
535	    return page;
536	}
537	
538	
539	static njs_mp_block_t *
540	njs_mp_alloc_cluster(njs_mp_t *mp)
541	{
542	    njs_uint_t      n;
543	    njs_mp_block_t  *cluster;
544	
545	    n = mp->cluster_size >> mp->page_size_shift;
546	
547	    cluster = njs_zalloc(sizeof(njs_mp_block_t) + n * sizeof(njs_mp_page_t));
548	
549	    if (njs_slow_path(cluster == NULL)) {
550	        return NULL;
551	    }
552	
553	    /* NJS_MP_CLUSTER_BLOCK type is zero. */
554	
555	    cluster->size = mp->cluster_size;
556	
557	    cluster->start = njs_memalign(mp->page_alignment, mp->cluster_size);
558	    if (njs_slow_path(cluster->start == NULL)) {
559	        njs_free(cluster);
560	        return NULL;
561	    }
562	
563	    n--;
564	    cluster->pages[n].number = n;
565	    njs_queue_insert_head(&mp->free_pages, &cluster->pages[n].link);
566	
567	    while (n != 0) {
568	        n--;
569	        cluster->pages[n].number = n;
570	        njs_queue_insert_before(&cluster->pages[n + 1].link,
571	                                &cluster->pages[n].link);
572	    }
573	
574	    njs_rbtree_insert(&mp->blocks, &cluster->node);
575	
576	    return cluster;
577	}
578	
579	#endif
580	
581	
582	static void *
583	njs_mp_alloc_large(njs_mp_t *mp, size_t alignment, size_t size)
584	{
585	    u_char          *p;
586	    size_t          aligned_size;
587	    uint8_t         type;
588	    njs_mp_block_t  *block;
589	
590	    /* Allocation must be less than 4G. */
591	    if (njs_slow_path(size >= UINT32_MAX)) {
592	        return NULL;
593	    }
594	
595	#if (NJS_DEBUG)
596	    /*
597	     * Ensure that the size is not zero, otherwise njs_mp_find_block()
598	     * will not be able to find the block.
599	     */
600	    size += size == 0;
601	#endif
602	
603	    if (njs_is_power_of_two(size)) {
604	        block = njs_malloc(sizeof(njs_mp_block_t));
605	        if (njs_slow_path(block == NULL)) {
606	            return NULL;
607	        }
608	
609	        p = njs_memalign(alignment, size);
610	        if (njs_slow_path(p == NULL)) {
611	            njs_free(block);
612	            return NULL;
613	        }
614	
615	        type = NJS_MP_DISCRETE_BLOCK;
616	
617	    } else {
618	        aligned_size = njs_align_size(size, sizeof(uintptr_t));
619	
620	        p = njs_memalign(alignment, aligned_size + sizeof(njs_mp_block_t));
621	        if (njs_slow_path(p == NULL)) {
622	            return NULL;
623	        }
624	
625	        block = (njs_mp_block_t *) (p + aligned_size);
626	        type = NJS_MP_EMBEDDED_BLOCK;
627	    }
628	
629	    block->type = type;
630	    block->size = size;
631	    block->start = p;
632	
633	    njs_rbtree_insert(&mp->blocks, &block->node);
634	
635	    return p;
636	}
