639	static intptr_t
640	njs_mp_rbtree_compare(njs_rbtree_node_t *node1, njs_rbtree_node_t *node2)
641	{
642	    njs_mp_block_t  *block1, *block2;
643	
644	    block1 = (njs_mp_block_t *) node1;
645	    block2 = (njs_mp_block_t *) node2;
646	
647	    return (uintptr_t) block1->start - (uintptr_t) block2->start;
648	}
649	
650	
651	njs_mp_cleanup_t *
652	njs_mp_cleanup_add(njs_mp_t *mp, size_t size)
653	{
654	    njs_mp_cleanup_t  *c;
655	
656	    c = njs_mp_alloc(mp, sizeof(njs_mp_cleanup_t));
657	    if (njs_slow_path(c == NULL)) {
658	        return NULL;
659	    }
660	
661	    if (size) {
662	        c->data = njs_mp_alloc(mp, size);
663	        if (njs_slow_path(c->data == NULL)) {
664	            return NULL;
665	        }
666	
667	    } else {
668	        c->data = NULL;
669	    }
670	
671	    c->handler = NULL;
672	    c->next = mp->cleanup;
673	
674	    mp->cleanup = c;
675	
676	    njs_debug_alloc("mp add cleanup: @%p\n", c);
677	
678	    return c;
679	}
680	
681	
682	void
683	njs_mp_free(njs_mp_t *mp, void *p)
684	{
685	    const char      *err;
686	    njs_mp_block_t  *block;
687	
688	    njs_debug_alloc("mp free: @%p\n", p);
689	
690	    block = njs_mp_find_block(&mp->blocks, p);
691	
692	    if (njs_fast_path(block != NULL)) {
693	
694	        if (block->type == NJS_MP_CLUSTER_BLOCK) {
695	            err = njs_mp_chunk_free(mp, block, p);
696	
697	            if (njs_fast_path(err == NULL)) {
698	                return;
699	            }
700	
701	        } else if (njs_fast_path(p == block->start)) {
702	            njs_rbtree_delete(&mp->blocks, &block->node);
703	
704	            if (block->type == NJS_MP_DISCRETE_BLOCK) {
705	                njs_free(block);
706	            }
707	
708	            njs_free(p);
709	
710	            return;
711	
712	        } else {
713	            njs_assert_msg(0, "freed pointer points to middle of blk: %p\n", p);
714	        }
715	
716	    } else {
717	        njs_assert_msg(p == NULL, "freed pointer is out of mp: %p\n", p);
718	    }
719	}
720	
721	
722	static njs_mp_block_t *
723	njs_mp_find_block(njs_rbtree_t *tree, u_char *p)
724	{
725	    njs_mp_block_t     *block;
726	    njs_rbtree_node_t  *node, *sentinel;
727	
728	    node = njs_rbtree_root(tree);
729	    sentinel = njs_rbtree_sentinel(tree);
730	
731	    while (node != sentinel) {
732	
733	        block = (njs_mp_block_t *) node;
734	
735	        if (p < block->start) {
736	            node = node->left;
737	
738	        } else if (p >= block->start + block->size) {
739	            node = node->right;
740	
741	        } else {
742	            return block;
743	        }
744	    }
745	
746	    return NULL;
747	}
748	
749	
750	static const char *
751	njs_mp_chunk_free(njs_mp_t *mp, njs_mp_block_t *cluster,
752	    u_char *p)
753	{
754	    u_char         *start;
755	    uintptr_t      offset;
756	    njs_uint_t     n, size, chunk;
757	    njs_mp_page_t  *page;
758	    njs_mp_slot_t  *slot;
759	
760	    n = (p - cluster->start) >> mp->page_size_shift;
761	    start = cluster->start + (n << mp->page_size_shift);
762	
763	    page = &cluster->pages[n];
764	
765	    if (page->size == 0) {
766	        return "freed pointer points to already free page: %p";
767	    }
768	
769	    size = page->size << mp->chunk_size_shift;
770	
771	    if (size != mp->page_size) {
772	
773	        offset = (uintptr_t) (p - start) & (mp->page_size - 1);
774	        chunk = offset / size;
775	
776	        if (njs_slow_path(offset != chunk * size)) {
777	            return "freed pointer points to wrong chunk: %p";
778	        }
779	
780	        if (njs_slow_path(njs_mp_chunk_is_free(page->map, chunk))) {
781	            return "freed pointer points to already free chunk: %p";
782	        }
783	
784	        njs_mp_chunk_set_free(page->map, chunk);
785	
786	        /* Find a slot with appropriate chunk size. */
787	        for (slot = mp->slots; slot->size < size; slot++) { /* void */ }
788	
789	        if (page->chunks != slot->chunks) {
790	            page->chunks++;
791	
792	            if (page->chunks == 1) {
793	                /*
794	                 * Add the page to the head of mp chunk slot list
795	                 * of pages with free chunks.
796	                 */
797	                njs_queue_insert_head(&slot->pages, &page->link);
798	            }
799	
800	            njs_mp_free_junk(p, size);
801	
802	            return NULL;
803	
804	        } else {
805	            /*
806	             * All chunks are free, remove the page from mp chunk slot
807	             * list of pages with free chunks.
808	             */
809	            njs_queue_remove(&page->link);
810	        }
811	
812	    } else if (njs_slow_path(p != start)) {
813	        return "invalid pointer to chunk: %p";
814	    }
815	
816	    /* Add the free page to the mp's free pages tree. */
817	
818	    page->size = 0;
819	    njs_queue_insert_head(&mp->free_pages, &page->link);
820	
821	    njs_mp_free_junk(p, size);
822	
823	    /* Test if all pages in the cluster are free. */
824	
825	    page = cluster->pages;
826	    n = mp->cluster_size >> mp->page_size_shift;
827	
828	    do {
829	         if (page->size != 0) {
830	             return NULL;
831	         }
832	
833	         page++;
834	         n--;
835	    } while (n != 0);
836	
837	    /* Free cluster. */
838	
839	    page = cluster->pages;
840	    n = mp->cluster_size >> mp->page_size_shift;
841	
842	    do {
843	         njs_queue_remove(&page->link);
844	         page++;
845	         n--;
846	    } while (n != 0);
847	
848	    njs_rbtree_delete(&mp->blocks, &cluster->node);
849	
850	    p = cluster->start;
851	
852	    njs_free(cluster);
853	    njs_free(p);
854	
855	    return NULL;
856	}
