225	static njs_flathsh_descr_t *
226	njs_expand_elts(njs_flathsh_query_t *fhq, njs_flathsh_descr_t *h)
227	{
228	    void                 *chunk;
229	    size_t               size, new_elts_size, new_hash_size;
230	    uint32_t             new_hash_mask, i;
231	    njs_int_t            cell_num;
