234	
235	    new_elts_size = h->elts_size * (size_t) NJS_FLATHSH_ELTS_EXPAND_FACTOR_NUM /
236	                                          NJS_FLATHSH_ELTS_EXPAND_FACTOR_DENOM;
237	
238	    new_elts_size = njs_max(h->elts_count + 1ul, new_elts_size);
239	
240	    new_hash_size = h->hash_mask + 1ul;
241	
242	    while (new_hash_size < new_elts_size) {
243	        new_hash_size = 2 * new_hash_size;
244	    }
245	
246	    /* Overflow check. */
247	
248	    if (njs_slow_path(new_hash_size > UINT32_MAX)) {
249	        return NULL;
250	    }
251	
252	    if (new_hash_size != (h->hash_mask + 1)) {
253	
254	        /* Expand both hash table cells and its elts. */
255	
256	        h_src = h;
257	        size = njs_flathsh_chunk_size(new_hash_size, new_elts_size);
258	        chunk = njs_flathsh_malloc(fhq, size);
259	        if (njs_slow_path(chunk == NULL)) {
260	            return NULL;
261	        }
262	
263	        h = njs_flathsh_descr(chunk, new_hash_size);
264	
265	        memcpy(h, h_src, sizeof(njs_flathsh_descr_t) +
266	               sizeof(njs_flathsh_elt_t) * h_src->elts_size);
267	
268	        new_hash_mask = new_hash_size - 1;
269	        h->hash_mask = new_hash_mask;
270	        njs_memzero(chunk, sizeof(uint32_t) * new_hash_size);
271	
272	        for (i = 0, elt = njs_hash_elts(h); i < h->elts_count; i++, elt++) {
273	            if (elt->type != NJS_FREE_FLATHSH_ELEMENT) {
274	                cell_num = elt->key_hash & new_hash_mask;
275	                elt->next_elt = njs_hash_cells_end(h)[-cell_num - 1];
276	                njs_hash_cells_end(h)[-cell_num - 1] = i + 1;
277	            }
278	        }
279	
280	        njs_flathsh_free(fhq, njs_flathsh_chunk(h_src));
281	
282	    } else {
283	
284	        size = njs_flathsh_chunk_size(new_hash_size, new_elts_size);
285	
286	        /* Expand elts only. */
287	#ifdef NJS_FLATHSH_USE_SYSTEM_ALLOCATOR
288	        chunk = realloc(njs_flathsh_chunk(h), size);
289	        if (njs_slow_path(chunk == NULL)) {
290	            return NULL;
291	        }
292	
293	#else
294	        chunk = fhq->proto->alloc(fhq->pool, size);
295	        if (njs_slow_path(chunk == NULL)) {
296	            return NULL;
297	        }
298	
299	        memcpy(chunk, njs_flathsh_chunk(h),
300	               njs_flathsh_chunk_size(h->hash_mask + 1, h->elts_size));
301	
302	        fhq->proto->free(fhq->pool, njs_flathsh_chunk(h), 0);
303	#endif
304	        h = njs_flathsh_descr(chunk, new_hash_size);
305	    }
306	
307	    h->elts_size = new_elts_size;
308	
309	    return h;
310	}
