477	static njs_flathsh_descr_t *
478	njs_shrink_elts(njs_flathsh_query_t *fhq, njs_flathsh_descr_t *h)
479	{
480	    void                 *chunk;
481	    njs_int_t            cell_num;
482	    uint32_t             i, j, new_hash_size, new_hash_mask, new_elts_size;
483	    njs_flathsh_elt_t    *elt, *elt_src;
484	    njs_flathsh_descr_t  *h_src;
485	
486	    new_elts_size = njs_max(NJS_FLATHSH_ELTS_INITIAL_SIZE,
487	                            h->elts_count - h->elts_deleted_count);
488	
489	    njs_assert(new_elts_size <= h->elts_size);
490	
491	    new_hash_size = h->hash_mask + 1;
492	    while ((new_hash_size / 2) >= new_elts_size) {
493	        new_hash_size = new_hash_size / 2;
494	    }
495	
496	    new_hash_mask = new_hash_size - 1;
497	
498	    h_src = h;
499	    chunk = njs_flathsh_malloc(fhq, njs_flathsh_chunk_size(new_hash_size,
500	                                                           new_elts_size));
501	    if (njs_slow_path(chunk == NULL)) {
502	        return NULL;
503	    }
504	
505	    h = njs_flathsh_descr(chunk, new_hash_size);
506	    memcpy(h, h_src, sizeof(njs_flathsh_descr_t));
507	
508	    njs_memzero(njs_hash_cells_end(h) - new_hash_size,
509	                sizeof(uint32_t) * new_hash_size);
510	
511	    elt_src = njs_hash_elts(h_src);
512	    for (i = 0, j = 0, elt = njs_hash_elts(h); i < h->elts_count; i++) {
513	        if (elt_src->type != NJS_FREE_FLATHSH_ELEMENT) {
514	            *elt = *elt_src;
515	            elt->key_hash = elt_src->key_hash;
516	
517	            cell_num = elt_src->key_hash & new_hash_mask;
518	            elt->next_elt = njs_hash_cells_end(h)[-cell_num - 1];
519	            njs_hash_cells_end(h)[-cell_num - 1] = j + 1;
520	            j++;
521	            elt++;
522	        }
523	
524	        elt_src++;
525	    }
526	
527	    njs_assert(j == (h->elts_count - h->elts_deleted_count));
528	
529	    h->hash_mask = new_hash_mask;
530	    h->elts_size = new_elts_size;
531	    h->elts_deleted_count = 0;
532	    h->elts_count = j;
533	
534	    njs_flathsh_free(fhq, njs_flathsh_chunk(h_src));
535	
536	    return h;
537	}
