541	njs_flathsh_delete(njs_flathsh_t *fh, njs_flathsh_query_t *fhq)
542	{
543	    njs_int_t            cell_num, elt_num;
544	    njs_flathsh_elt_t    *elt, *elt_prev, *elts;
545	    njs_flathsh_descr_t  *h;
546	
547	    h = fh->slot;
548	
549	    if (njs_slow_path(h == NULL)) {
550	        return NJS_DECLINED;
551	    }
552	
553	    cell_num = fhq->key_hash & h->hash_mask;
554	    elt_num = njs_hash_cells_end(h)[-cell_num - 1];
555	    elts = njs_hash_elts(h);
556	    elt_prev = NULL;
557	
558	    while (elt_num != 0) {
559	        elt = &elts[elt_num - 1];
560	
561	        if (elt->key_hash == fhq->key_hash &&
562	            fhq->proto->test(fhq, elt->value) == NJS_OK)
563	        {
564	            fhq->value = elt;
565	
566	            if (elt_prev != NULL) {
567	                elt_prev->next_elt = elt->next_elt;
568	
569	            } else {
570	                njs_hash_cells_end(h)[-cell_num - 1] = elt->next_elt;
571	            }
572	
573	            h->elts_deleted_count++;
574	
575	            elt->type = NJS_FREE_FLATHSH_ELEMENT;
576	
577	            /* Shrink elts if elts_deleted_count is eligible. */
578	
579	            if (h->elts_deleted_count >= NJS_FLATHSH_ELTS_MINIMUM_TO_SHRINK
580	                && h->elts_deleted_count
581	                   >= (h->elts_count / NJS_FLATHSH_ELTS_FRACTION_TO_SHRINK))
582	            {
583	                h = njs_shrink_elts(fhq, h);
584	                if (njs_slow_path(h == NULL)) {
585	                    return NJS_ERROR;
586	                }
587	
588	                fh->slot = h;
589	            }
590	
591	            if (h->elts_deleted_count == h->elts_count) {
592	                njs_flathsh_free(fhq, njs_flathsh_chunk(h));
593	                fh->slot = NULL;
594	            }
595	
596	            return NJS_OK;
597	        }
598	
599	        elt_prev = elt;
600	        elt_num = elt->next_elt;
601	    }
602	
603	    return NJS_DECLINED;
604	}
