643	
644	            if (h->elts_deleted_count >= NJS_FLATHSH_ELTS_MINIMUM_TO_SHRINK
645	                && h->elts_deleted_count
646	                   >= (h->elts_count / NJS_FLATHSH_ELTS_FRACTION_TO_SHRINK))
647	            {
648	                h = njs_shrink_elts(fhq, h);
649	                if (njs_slow_path(h == NULL)) {
650	                    return NJS_ERROR;
651	                }
