672	njs_flathsh_elt_t *
673	njs_flathsh_each(const njs_flathsh_t *fh, njs_flathsh_each_t *fhe)
674	{
675	    njs_flathsh_elt_t    *e, *elt;
676	    njs_flathsh_descr_t  *h;
